sleep() in a pthreaded function will return immediately if the program receives a signal.

How-To-Repeat: Run the following program and then SIGHUP the process. Each SIGHUP will produce the output of both sighup() and pthread1(), but not main() i.e. the sleep timer in the main thread is working properly.



/*********************************************************************************************************
***                                         pthread.c                                                  ***
***                                Pthread sleep bug demonstration                                     ***
**********************************************************************************************************/


#include<stdio.h>
#include<pthread.h>
#include<stdlib.h>

void    *pthread1()
{

while(1)
        {
        printf("pthread1\n");
        sleep(3600);
        }
}

void    sighup()
{

printf("Received SIGHUP\n");
}


void    quit()
{

printf("Received signal, quiting!\n");
exit(0);
}



int main()
{
int             rc;
pthread_t       thread1;
pthread_attr_t  thread1_attr;

signal(SIGHUP, &sighup);
signal(SIGQUIT, &quit);
signal(SIGKILL, &quit);
signal(SIGTERM, &quit);
pthread_attr_init(&thread1_attr);
rc = pthread_create(&thread1, NULL, pthread1, NULL);
while(1)
        {
        printf("main\n");
        sleep(3600);
        }

return 0;
}
